import { getAllAdapters } from "@rudel/agent-adapters";
import {
	type ClickHouseExecutor,
	escapeString,
	getClickhouse,
} from "../clickhouse.js";

export async function getOrgSessionCount(orgId: string): Promise<number> {
	const ch = getClickhouse();
	const escaped = escapeString(orgId);
	const tables = getAllAdapters().map((a) => a.rawTableName);
	const results = await Promise.all(
		tables.map((table) =>
			ch.query<{ count: string }>(
				`SELECT count() as count FROM ${table} WHERE organization_id = '${escaped}'`,
			),
		),
	);
	return results.reduce((sum, rows) => sum + Number(rows[0]?.count ?? 0), 0);
}

export async function deleteOrgSessions(orgId: string): Promise<void> {
	const ch = getClickhouse();
	const escaped = escapeString(orgId);
	const tables = getAllAdapters().map((a) => a.rawTableName);
	await Promise.all([
		...tables.map((table) =>
			ch.execute(`DELETE FROM ${table} WHERE organization_id = '${escaped}'`),
		),
		ch.execute(
			`DELETE FROM rudel.session_analytics WHERE organization_id = '${escaped}'`,
		),
	]);
}

export async function migrateOrgSessions(
	fromOrgId: string,
	toOrgId: string,
	ch: ClickHouseExecutor = getClickhouse(),
): Promise<void> {
	const from = escapeString(fromOrgId);
	const to = escapeString(toOrgId);
	const tables = getAllAdapters().map((a) => a.rawTableName);
	const ts = Date.now();

	// Can't use ALTER TABLE UPDATE — organization_id is an ORDER BY key and
	// ingested_at is the ReplacingMergeTree version column. Instead, copy rows
	// into a temp table with the new org, re-insert, then delete the originals.
	await Promise.all(
		tables.map(async (table) => {
			const suffix = table.replace("rudel.", "");
			const tempTable = `rudel._temp_migrate_${suffix}_${ts}`;
			await ch.execute(
				`CREATE TABLE ${tempTable} ENGINE = MergeTree() ORDER BY tuple() AS SELECT * REPLACE ('${to}' AS organization_id) FROM ${table} WHERE organization_id = '${from}'`,
			);
			await ch.execute(
				`INSERT INTO ${table} SELECT * FROM ${tempTable} SETTINGS async_insert=0`,
			);
			await ch.execute(
				`DELETE FROM ${table} WHERE organization_id = '${from}'`,
			);
			await ch.execute(`DROP TABLE IF EXISTS ${tempTable}`);
		}),
	);

	// The MVs on the raw tables already created new session_analytics rows
	// with the target org_id. Just delete the old ones.
	await ch.execute(
		`DELETE FROM rudel.session_analytics WHERE organization_id = '${from}'`,
	);
}

