export async function migrateOrgSessions(
	fromOrgId: string,
	toOrgId: string,
	ch: ClickHouseExecutor = getClickhouse(),
): Promise<void> {
	const from = escapeString(fromOrgId);
	const to = escapeString(toOrgId);
	const tables = getAllAdapters().map((a) => a.rawTableName);
	const ts = Date.now();

	// Can't use ALTER TABLE UPDATE — organization_id is an ORDER BY key and
	// ingested_at is the ReplacingMergeTree version column. Instead, copy rows
	// into a temp table with the new org, re-insert, then delete the originals.
	await Promise.all(
		tables.map(async (table) => {
			const suffix = table.replace("rudel.", "");
			const tempTable = `rudel._temp_migrate_${suffix}_${ts}`;
			await ch.execute(
				`CREATE TABLE ${tempTable} ENGINE = MergeTree() ORDER BY tuple() AS SELECT * REPLACE ('${to}' AS organization_id) FROM ${table} WHERE organization_id = '${from}'`,
			);
			await ch.execute(
				`INSERT INTO ${table} SELECT * FROM ${tempTable} SETTINGS async_insert=0`,
			);
			await ch.execute(`DROP TABLE IF EXISTS ${tempTable}`);
		}),
	);

	// Delete old rows. On ClickHouse Cloud, DELETE mutations may outlast the
	// HTTP gateway timeout (504) but still run to completion server-side.
	// Fire all deletes in parallel and don't let a gateway timeout abort the
	// migration — the INSERT above already succeeded.
	const deletions = [
		...tables.map((table) =>
			ch.execute(
				`DELETE FROM ${table} WHERE organization_id = '${from}'`,
			),
		),
		ch.execute(
			`DELETE FROM rudel.session_analytics WHERE organization_id = '${from}'`,
		),
	];
	const results = await Promise.allSettled(deletions);
	for (const r of results) {
		if (r.status === "rejected") {
			console.warn(
				`[migrateOrgSessions] DELETE mutation may still be running: ${r.reason}`,
			);
		}
	}
}

