248:	extractTimestamps(content: string): {
249:		sessionDate: string;
250:		lastInteractionDate: string;
251:	} | null {
252:		let min: string | null = null;
253:		let max: string | null = null;
254:
255:		for (const line of content.split("\n")) {
256:			if (!line) continue;
257:			let parsed: { type?: string; timestamp?: string };
258:			try {
259:				parsed = JSON.parse(line);
260:			} catch {
261:				continue;
262:			}
263:			if (
264:				(parsed.type === "user" || parsed.type === "assistant") &&
265:				parsed.timestamp
266:			) {
267:				const ts = parsed.timestamp;
268:				if (!min || ts < min) min = ts;
269:				if (!max || ts > max) max = ts;
270:			}
271:		}
272:
273:		if (!min || !max) return null;
274:
275:		return { sessionDate: min, lastInteractionDate: max };
